\textit{Source: Landesman--Litt, \S1.}
  A local system $\bV$ (or flat vector bundle) has \emph{infinite monodromy} if
  its monodromy group $\rho(\pi_1(X))$ is infinite.

\textit{Source: Landesman--Litt, \S2.3.}
  A parabolic bundle $E_\star$ is \emph{parabolically semistable}
  (respectively \emph{stable}) if $\mu_\star(F_\star) \leq \mu_\star(E_\star)$
  (respectively $\mu_\star(F_\star) < \mu_\star(E_\star)$) for every parabolic
  subbundle $F_\star \subset E_\star$, with the induced parabolic structure of
  \cref{def:induced-subbundle}.

\textit{Source: Landesman--Litt, \S2.3.}
  For a parabolic sheaf $F_\star$, the \emph{parabolic dual} is
  $F^\vee_\star := \sheafhom(F_\star, \sO_X)_\star$.

\textit{Source: Landesman--Litt, \S3.5.}
  Let $\on{Def}_{(C,D)}: \on{Art}_\C \to \on{Set}$ be the functor sending a local
  Artin $\C$-algebra $(A,\mathfrak{m},\kappa)$ to the set of flat deformations of
  $(C,D)$ over $A$: tuples $(\sC,\mathscr{D},q,f)$ with $q: \sC \to \Spec A$
  flat, $\mathscr{D} \subset \sC$ a relative Cartier divisor over $\Spec A$, and
  $f: C \to \sC$ inducing an isomorphism $C \xrightarrow{\sim} \sC \times_{\Spec A}
  \Spec \kappa$ carrying $D$ isomorphically to $\mathscr{D} \times_{\Spec A}
  \Spec \kappa$.

\textit{Source: MR4736527 (arXiv:2202.00039), §1, Theorem counterexample.}

  Let \(g \geq 2\) be an integer. There exists a vector bundle with flat
  connection \((\sF, \nabla)\) on \(\sM_{g,1}\) such that for each fiber \(C\) of
  the forgetful morphism \(\sM_{g,1} \to \sM_g\), the restriction
  \((\sF, \nabla)|_C\)
  \begin{enumerate}
    \item has semisimple monodromy, and
    \item is not semistable.
  \end{enumerate}
